1	//! Serial transaction helpers — send a command and read its reply.
2	//!
3	//! - `read_reply` does deadline-bounded raw reads so unmatched garbage
4	//!   can't block forever.
5	//! - `transact` / `transact_retry` send a command and validate the reply
6	//!   (checksum, `$VNERR`); `send_reboot_command` tolerates a missing echo.
7	
8	use std::io::{Read, Write};
9	use std::time::{Duration, Instant};
10	
11	use crate::proto::{verify_checksum, vnerr_message};
12	
13	/// Read from the device until `matches` accepts a line or the deadline passes.
14	///
15	/// Reads raw bytes (not `read_line`) so a stream of garbage with no newline —
16	/// e.g. when the host baud doesn't match the device — can't block us forever:
17	/// we honor an overall `deadline` and cap line length to drop runaway junk.
18	pub fn read_reply<R, F>(
19	    reader: &mut R,
20	    deadline: Instant,
21	    mut matches: F,
22	) -> std::io::Result<Option<String>>
23	where
24	    R: Read,
25	    F: FnMut(&str) -> bool,
26	{
27	    let mut buf = [0u8; 256];
28	    let mut line: Vec<u8> = Vec::new();
29	    loop {
30	        if Instant::now() >= deadline {
31	            return Ok(None);
32	        }
33	        let n = match reader.read(&mut buf) {
34	            // On a serial port there is no real EOF: a read that yields nothing
35	            // (Ok(0), or a TimedOut/WouldBlock error) just means "no data within
36	            // this read window". Keep waiting — the overall `deadline` is the only
37	            // terminator, so a reply that lags (e.g. while the device reconfigures
38	            // its UART for a baud change) isn't dropped.
39	            Ok(0) => continue,
40	            Ok(n) => n,
41	            Err(ref e)
42	                if matches!(
43	                    e.kind(),
44	                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
45	                ) =>
46	            {
47	                continue;
48	            }
49	            Err(e) => return Err(e),
50	        };
51	        for &b in &buf[..n] {
52	            match b {
53	                b'\n' => {
54	                    let raw = String::from_utf8_lossy(&line);
55	                    // An ASCII reply ($VN...*XX) can arrive with leading bytes on
56	                    // the same line — e.g. binary frames still streaming when the
57	                    // echo lands. The reply starts at the last '$', so slice there
58	                    // before matching/validating.
59	                    let candidate: String = match raw.rfind('$') {
60	                        Some(p) => raw[p..].trim().to_string(),
61	                        None => raw.trim().to_string(),
62	                    };
63	                    line.clear();
64	                    if matches(&candidate) {
65	                        return Ok(Some(candidate));
66	                    }
67	                }
68	                b'\r' => {}
69	                _ => {
70	                    line.push(b);
71	                    if line.len() > 1024 {
72	                        line.clear(); // drop a runaway (likely garbage) line
73	                    }
74	                }
75	            }
76	        }
77	    }
78	}
79	
80	/// Send `cmd`, wait up to `wait` for a reply matching `accept`, and validate it.
81	/// A `$VNERR` reply is surfaced as an error; a checksum mismatch is rejected.
82	pub fn transact<S: Read + Write>(
83	    port: &mut S,
84	    cmd: &str,
85	    wait: Duration,
86	    accept: impl Fn(&str) -> bool,
87	    missing: &str,
88	) -> Result<String, Box<dyn std::error::Error>> {
89	    print!("TX: {cmd}");
90	    port.write_all(cmd.as_bytes())?;
91	    port.flush()?;
92	
93	    let deadline = Instant::now() + wait;
94	    let reply = read_reply(port, deadline, |l| accept(l) || l.starts_with("$VNERR"))?
95	        .ok_or_else(|| missing.to_string())?;
96	    verify_checksum(&reply)?;
97	    if reply.starts_with("$VNERR") {
98	        return Err(vnerr_message(&reply).into());
99	    }
100	    Ok(reply)
101	}
102	
